class Solution {
    public boolean equalFrequency(String word) {
        int[] freq = new int[26];
        for (char c : word.toCharArray()) freq[c - 'a']++;

        for (int i = 0; i < word.length(); i++) {
            int idx = word.charAt(i) - 'a';
            freq[idx]--;

            int target = -1;
            boolean ok = true;
            for (int f : freq) {
                if (f == 0) continue;
                if (target == -1) target = f;
                else if (f != target) { ok = false; break; }
            }
            if (ok) return true;

            freq[idx]++;
        }
        return false;
    }
}
```
